import{_ as i,o as a,c as s,a0 as n}from"./chunks/framework.M0_h-cZU.js";const p=JSON.parse('{"title":"Nuxt3 學習筆記 - Ryan","description":"","frontmatter":{"title":"Nuxt3 學習筆記 - Ryan"},"headers":[],"relativePath":"pages/f2e/docVue/nuxt/nuxt3/nuxt3-28.md","filePath":"pages/f2e/docVue/nuxt/nuxt3/nuxt3-28.md"}'),l={name:"pages/f2e/docVue/nuxt/nuxt3/nuxt3-28.md"};function t(d,e,o,r,c,u){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="_28-渲染模式-rendering-modes-與網站使用體驗核心指標-core-web-vitals" tabindex="-1">28. 渲染模式 (Rendering modes) 與網站使用體驗核心指標 (Core Web Vitals) <a class="header-anchor" href="#_28-渲染模式-rendering-modes-與網站使用體驗核心指標-core-web-vitals" aria-label="Permalink to &quot;28. 渲染模式 (Rendering modes) 與網站使用體驗核心指標 (Core Web Vitals)&quot;">​</a></h1><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><ul><li><p><code>Nuxt 3</code> 作為一個完整的全端框架，兼具開箱即用的特性。</p></li><li><p>當選擇 <code>Nuxt 3</code> 開發網站準備建構正式環境專案時，開發者可以根據使用方式與解決情境，選擇是否啟用伺服器端渲染（<code>SSR</code>），或單純產生靜態頁面做 <code>SSG</code>。</p></li><li><p>本篇主要講述 <code>Nuxt 3</code> 所提供的渲染模式以及如何進行選擇。</p></li></ul><h2 id="nuxt-3-的渲染模式" tabindex="-1">Nuxt 3 的渲染模式 <a class="header-anchor" href="#nuxt-3-的渲染模式" aria-label="Permalink to &quot;Nuxt 3 的渲染模式&quot;">​</a></h2><ul><li><p>根據官方文件介紹，<code>Nuxt 3</code> 目前支援的渲染模式包含「<code>僅在客戶端渲染（Client-side Only Rendering）</code>」與「<code>通用渲染（Universal Rendering）</code>」。</p></li><li><h3 id="通用渲染-universal-rendering" tabindex="-1">通用渲染 (Universal Rendering) <a class="header-anchor" href="#通用渲染-universal-rendering" aria-label="Permalink to &quot;通用渲染 (Universal Rendering)&quot;">​</a></h3><ul><li><code>Nuxt 3</code> 預設的配置為：<code>export default defineNuxtConfig({ ssr: true })</code>，即預設為 <code>SSR 通用渲染模式</code>。</li></ul><div class="language-ts vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> default</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> defineNuxtConfig</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ssr: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></li><li><h3 id="僅在客戶端渲染-client-side-only-rendering" tabindex="-1">僅在客戶端渲染 (Client-side Only Rendering) <a class="header-anchor" href="#僅在客戶端渲染-client-side-only-rendering" aria-label="Permalink to &quot;僅在客戶端渲染 (Client-side Only Rendering)&quot;">​</a></h3><ul><li><p>如果想關閉 <code>SSR</code>、只在客戶端進行渲染，可將 <code>nuxt.config.ts</code> 中的 <code>ssr</code> 屬性設為 <code>false</code>。</p></li><li><p>整個專案建構後，運作模式就如同純 Vue 建立出來的 <code>單頁應用程式（SPA）</code>，除了首頁的容器頁面，畫面的渲染與響應操作都會在客戶端完成。</p></li></ul></li></ul><h2 id="nuxt-3-的靜態頁面生成-static-site-generation-ssg" tabindex="-1">Nuxt 3 的靜態頁面生成 (Static Site Generation, SSG) <a class="header-anchor" href="#nuxt-3-的靜態頁面生成-static-site-generation-ssg" aria-label="Permalink to &quot;Nuxt 3 的靜態頁面生成 (Static Site Generation, SSG)&quot;">​</a></h2><ul><li><p><code>Nuxt 3</code> 在 <code>v3.0.0-rc.10</code> 版本實現了「<code>全靜態生成（Full Static Generation）</code>」，這才擁有了完全的靜態化，解決了早期版本在静態頁面下仍需發送 API 獲取資料的問題。</p></li><li><p>透過 <code>Nuxt</code> 產生的靜態頁面，會在建構階段將所有 <code>.vue</code> 頁面所需的 <code>JavaScript</code>、樣式或檔案進行組織與 <code>預渲染（Pre-rendering）</code>。</p></li><li><p>最重要的是，頁面或元件內需要透過 <code>API</code> 請求資料的地方，也會一併在建構時取得這些資料，並添加進各自的 <code>HTML</code> 頁面與對應的 <code>Payload</code> 之中。</p></li></ul><h2 id="混合渲染-hybrid-rendering" tabindex="-1">混合渲染 (Hybrid Rendering) <a class="header-anchor" href="#混合渲染-hybrid-rendering" aria-label="Permalink to &quot;混合渲染 (Hybrid Rendering)&quot;">​</a></h2><ul><li><p><code>Nuxt 3</code> 提供「混合渲染」模式，用以增進各個路由頁面所需的渲染策略。</p></li><li><p>其概念是允許「<code>每個路由能有不同的渲染策略</code>」。例如：文章瀏覽頁面想以靜態頁面（SSG）產生，而管理後台只需要客戶端渲染（CSR）。開發者只需透過指定路由及設定屬性，就能在建構時自動完成自訂的策略並生成頁面。</p></li><li><p><code>Nuxt</code> 官方預期在 <code>nuxt.config</code> 提供 <code>routeRules</code> 來設定不同頁面的渲染策略，例如：</p><div class="language-ts vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> default</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> defineNuxtConfig</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  routeRules: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &#39;/&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { prerender: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 每一次建構時，都重新預渲染頁面</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div></li></ul><h2 id="網站使用體驗核心指標-core-web-vitals" tabindex="-1">網站使用體驗核心指標 (Core Web Vitals) <a class="header-anchor" href="#網站使用體驗核心指標-core-web-vitals" aria-label="Permalink to &quot;網站使用體驗核心指標 (Core Web Vitals)&quot;">​</a></h2><ul><li><h3 id="largest-contentful-paint-lcp-最大內容繪製" tabindex="-1">Largest Contentful Paint (LCP) 最大內容繪製 <a class="header-anchor" href="#largest-contentful-paint-lcp-最大內容繪製" aria-label="Permalink to &quot;Largest Contentful Paint (LCP) 最大內容繪製&quot;">​</a></h3> 主要用以衡量網頁的「<code>載入速度</code>」。當進入網站時，網頁會開始載入文字、圖片等並繪製畫面元素。當可視區域不再有新的、更大的元素載入後，LCP 時間才截止。若使用者等待大圖的時間過長，容易導致體驗不佳。建議控制在開始載入後的 <code>2.5 秒內</code>。</li><li><h3 id="first-input-delay-fid-首次輸入延遲" tabindex="-1">First Input Delay (FID) 首次輸入延遲 <a class="header-anchor" href="#first-input-delay-fid-首次輸入延遲" aria-label="Permalink to &quot;First Input Delay (FID) 首次輸入延遲&quot;">​</a></h3> 主要用以衡量使用者能在網站上進行操作的時間，也稱為「<code>網站可進行互動的時間</code>」。當使用者點擊連結、按鈕而驅動了 JavaScript 操作事件，直到瀏覽器做出回應並能實際處理事件所經過的時間即為 FID。為了良好體驗，建議控制在 <code>100 毫秒以內</code>。</li><li><h3 id="cumulative-layout-shift-cls-累計布局排版偏移" tabindex="-1">Cumulative Layout Shift (CLS) 累計布局排版偏移 <a class="header-anchor" href="#cumulative-layout-shift-cls-累計布局排版偏移" aria-label="Permalink to &quot;Cumulative Layout Shift (CLS) 累計布局排版偏移&quot;">​</a></h3> 衡量網頁布局排版的「<code>視覺穩定性</code>」。若使用者在網頁上點擊物件時，因為某些原因跳出新元素導致物件位置被擠壓、發生位移，會造成使用者誤觸非預期位置。此數值建議應控制在位移比例 <code>低於 0.1 秒內</code>。</li></ul><h3 id="nuxt-3-渲染模式與網站使用體驗核心指標" tabindex="-1">Nuxt 3 渲染模式與網站使用體驗核心指標 <a class="header-anchor" href="#nuxt-3-渲染模式與網站使用體驗核心指標" aria-label="Permalink to &quot;Nuxt 3 渲染模式與網站使用體驗核心指標&quot;">​</a></h3><ul><li>在核心指標中，<code>LCP（最大內容繪製）</code> 與 <code>FID（首次輸入延遲）</code> 這兩項指標，與 <code>Nuxt 3</code> 渲染模式的選擇最為相關。</li><li>選擇 <code>SSR</code> 不光只是為了解決 <code>SEO</code> 的問題，還需要考量使用者的體驗。 <ul><li>例如：選擇「通用渲染」來製作 SSR + SPA，雖然解決了 SEO 且讓網頁第一次就能完整顯示出來，但在 Vue 的 JavaScript 載入之前，網站其實是不具有互動性的，必須直至 <code>Hydration（客戶端活化/注水）</code> 步驟完成，使用者才能操作網頁上的元件。</li></ul></li><li>這種選擇會直接引發 <code>首次內容繪製（FCP）</code> 與 <code>可互動時間（TTI）</code>的平衡問題，而 <code>LCP</code> 與 <code>FID</code> 也通常發生在這之間。</li><li>因此，<code>SSR</code> + <code>SPA</code> 並非萬用解，開發者仍需因應各種情境搭配使用 <code>SSG</code>、<code>ISR</code> 等不同的渲染方式。<code>Nuxt 3</code> 幫忙應付了多數可能遇到的使用情境與痛點，開發者可依據需求靈活調整各頁面或整站的渲染方式。</li></ul><h3 id="小結" tabindex="-1">小結 <a class="header-anchor" href="#小結" aria-label="Permalink to &quot;小結&quot;">​</a></h3><ul><li>本篇總結了 <code>Nuxt 3</code> 支援的各種渲染模式（<code>CSR</code>、<code>Universal、Hybrid</code>）及其特點。</li><li>開發者在佈署正式專案時，不應盲目選擇單一模式，而應結合網站使用體驗核心指標（Core Web Vitals）的考量，針對不同類型的路由（如前台文章與後台管理）配置最合適的渲染策略，以兼顧 <code>SEO</code>、<code>載入速度</code> 與 <code>互動流暢度</code>。</li></ul>`,15)])])}const k=i(l,[["render",t]]);export{p as __pageData,k as default};
